import React from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight } from 'lucide-react';

function Navbar() {
  const [isOpen, setIsOpen] = React.useState(false);

  return (
    <nav className="bg-zinc-950 py-4 md:py-6 lg:py-8">
      <div className="container mx-auto flex justify-between items-center">
        <Link to="/" className="text-zinc-100 text-lg font-bold">NexaShop</Link>
        <button className="md:hidden" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <ArrowRight size={24} className="text-zinc-100" /> : <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-zinc-100" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M4 6h16M4 12h8m-8 6h16" />
          </svg>}
        </button>
        <ul className={`md:flex md:items-center ${isOpen ? 'block' : 'hidden'} md:block`}>
          <li className="md:ml-6 lg:ml-8">
            <Link to="/" className="text-zinc-100 hover:text-emerald-500 transition duration-300">Home</Link>
          </li>
          <li className="md:ml-6 lg:ml-8">
            <Link to="/" className="text-zinc-100 hover:text-emerald-500 transition duration-300">Features</Link>
          </li>
          <li className="md:ml-6 lg:ml-8">
            <Link to="/" className="text-zinc-100 hover:text-emerald-500 transition duration-300">Pricing</Link>
          </li>
        </ul>
      </div>
    </nav>
  );
}

export default Navbar;

