            <div key={index} className="bg-zinc-900 p-4 md:p-6 lg:p-8 mb-4 md:mb-6 lg:mb-8 md:mr-4 lg:mr-6 rounded-2xl shadow-md shadow-zinc-800/50 transition duration-300 hover:scale-105">
